import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {
    public static void main(String[] args) {
        // Simulating user input from a form
        String userInput = "<script>alert('XSS attack!')</script>";

        // Escaping user input using Apache Commons Text library
        String escapedUserInput = StringEscapeUtils.escapeHtml4(userInput);

        // Properly handling and displaying the escaped user input
        String output = "Welcome, " + escapedUserInput;

        // Printing the output to the console
        System.out.println(output);
    }
}

